        // Ensure the resolved path is still within the base directory to prevent Path Traversal attacks (e.g., accessing ../../../etc/passwd)
        if (!filePath.normalize().startsWith(baseDir.normalize())) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }

        try {
            // 3. Read the file content into a byte array
            byte[] fileContent = Files.readAllBytes(filePath);

            // 4. Return the content with the correct Content-Type header
            // Assuming the file is text (you would adjust this based on actual file type)
            return ResponseEntity.ok()
                    .contentType(org.springframework.http.MediaType.TEXT_PLAIN) 
                    .body(fileContent);

