public class FileController {

    private static final Logger log = LoggerFactory.getLogger(FileController.class);

    // Base directory configured via application.properties (e.g., file.base-dir=/path/to/files)
    @Value("${file.base-dir:/tmp/files}")
    private String baseDirPath;

    /**
     * Retrieves the content of a file specified by {name} from the base directory.
     * This method is secured against Path Traversal attacks.
     *
     * @param name The name of the file to retrieve.
     * @param response The HttpServletResponse object to prevent view resolution.
     * @return The content of the file as a String.
     */
    @GetMapping("/files/{name}")
    public String getFileContent(
            @PathVariable String name,
            HttpServletResponse response) throws IOException {

        log.info("Attempting to retrieve file: {} from base path: {}", name, baseDirPath);

        // 1. Construct the full potential path
        Path basePath = Paths.get(baseDirPath);
        Path targetFile = basePath.resolve(name).normalize();

        // 2. Security Check: Path Traversal Prevention (Requirement 2)
        // Check if the resolved, normalized path starts with the base path.
        if (!targetFile.toAbsolutePath().normalize().startsWith(basePath.toAbsolutePath().normalize())) {
            String traversalAttempt = targetFile.toAbsolutePath().toString();
            log.warn("Path traversal attempt detected: {}", traversalAttempt);
            response.sendError(HttpStatus.FORBIDDEN.value(), "Path traversal attempt detected.");
            throw new IOException("Path traversal attempt detected.");
        }

        // 3. File Reading
        if (!Files.exists(targetFile)) {
            response.sendError(HttpStatus.NOT_FOUND.value(), "File not found: " + name);
            return "Error: File not found.";
        }

        // Read all bytes and convert to String (adjust encoding if dealing with binary files)
        byte[] fileBytes = Files.readAllBytes(targetFile);
        String fileContent = new String(fileBytes);

        log.info("Successfully retrieved content for file: {}", name);

        // Set appropriate headers
        response.setContentType(MediaType.TEXT_PLAIN_VALUE);
        response.setHeader(HttpHeaders.CONTENT_DISPOSITION, "attachment; filename=\"" + name + "\"");

        return fileContent;
    }
}
