import org.w3c.dom.Document;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import org.xml.sax.InputSource;
import org.xml.sax.SAXException;

import java.io.IOException;
import java.io.InputStream;

/**
 * Utility class for securely parsing XML configuration documents.
 */
public class XmlConfigParser {

    /**
     * Parses an XML configuration document from an InputStream securely.
     *
     * SECURITY NOTE: This method is hardened against XXE attacks by explicitly
     * disabling DTD processing and external entity resolution.
     *
     * @param in The InputStream containing the XML configuration.
     * @return The parsed Document object.
     * @throws ParserConfigurationException If a DocumentBuilder cannot be created.
     * @throws SAXException If any error occurs during XML parsing.
     * @throws IOException If an I/O error occurs reading the stream.
     */
    public Document parseConfig(InputStream in) 
            throws ParserConfigurationException, SAXException, IOException {

        // 1. Get the DocumentBuilderFactory instance
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // --- SECURITY HARDENING ---
        // Disable DTD processing entirely to prevent XXE attacks.
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

        // Disable external entity resolution (although disallowing DOCTYPE often handles this, 
        // this adds an extra layer of defense if the feature setting isn't universally supported).
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
